const { DynamoDBClient, UpdateItemCommand } = require("@aws-sdk/client-dynamodb");
const { marshall } = require("@aws-sdk/util-dynamodb");

const DEFAULT_TIMEOUT_MS = 8000;

const dynamo = new DynamoDBClient({});

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchWithTimeout(url, options = {}, timeoutMs = DEFAULT_TIMEOUT_MS) {
  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, { ...options, signal: controller.signal });
    return res;
  } finally {
    clearTimeout(t);
  }
}

async function callPaymentApi(order, env) {
  const url = env.PAYMENT_API_URL;
  if (!url) throw new Error("PAYMENT_API_URL is not set");

  const headers = {
    "content-type": "application/json",
  };

  if (env.PAYMENT_API_KEY) headers["authorization"] = `Bearer ${env.PAYMENT_API_KEY}`;

  const body = JSON.stringify({
    orderId: order.orderId,
    amount: order.amount,
    currency: order.currency || "USD",
    customerId: order.customerId,
    paymentMethodId: order.paymentMethodId,
    idempotencyKey: order.idempotencyKey || order.orderId,
    metadata: order.metadata || {},
  });

  const res = await fetchWithTimeout(
    url,
    {
      method: "POST",
      headers,
      body,
    },
    Number(env.PAYMENT_API_TIMEOUT_MS || DEFAULT_TIMEOUT_MS)
  );

  const text = await res.text();
  let json;
  try {
    json = text ? JSON.parse(text) : {};
  } catch {
    json = { raw: text };
  }

  if (!res.ok) {
    const err = new Error(`Payment API error: ${res.status} ${res.statusText}`);
    err.details = json;
    err.status = res.status;
    throw err;
  }

  return json;
}

async function updateOrderInDynamo(order, paymentResult, env) {
  const tableName = env.ORDERS_TABLE;
  if (!tableName) throw new Error("ORDERS_TABLE is not set");

  const pkName = env.ORDERS_PK_NAME || "pk";
  const skName = env.ORDERS_SK_NAME || "sk";

  const pkValue = order[pkName] || `ORDER#${order.orderId}`;
  const skValue = order[skName] || `ORDER#${order.orderId}`;

  const now = new Date().toISOString();

  const exprNames = {
    "#status": "status",
    "#updatedAt": "updatedAt",
    "#payment": "payment",
  };

  const exprValues = marshall(
    {
      ":status": "PAID",
      ":updatedAt": now,
      ":payment": {
        provider: paymentResult.provider || paymentResult.gateway || "external",
        transactionId: paymentResult.transactionId || paymentResult.id || null,
        raw: paymentResult,
      },
    },
    { removeUndefinedValues: true }
  );

  const cmd = new UpdateItemCommand({
    TableName: tableName,
    Key: marshall({ [pkName]: pkValue, [skName]: skValue }),
    UpdateExpression: "SET #status = :status, #updatedAt = :updatedAt, #payment = :payment",
    ExpressionAttributeNames: exprNames,
    ExpressionAttributeValues: exprValues,
  });

  await dynamo.send(cmd);
}

function parseOrderFromRecord(record) {
  const body = record.body || "";
  const order = JSON.parse(body);
  if (!order || typeof order !== "object") throw new Error("Invalid order payload");
  if (!order.orderId) throw new Error("Missing orderId");
  if (order.amount == null) throw new Error("Missing amount");
  return order;
}

async function processRecord(record, env) {
  const order = parseOrderFromRecord(record);

  const paymentResult = await callPaymentApi(order, env);

  await updateOrderInDynamo(order, paymentResult, env);

  return { orderId: order.orderId, ok: true };
}

exports.handler = async (event, context) => {
  const env = process.env;
  const records = Array.isArray(event?.Records) ? event.Records : [];

  const concurrency = Math.max(1, Math.min(Number(env.CONCURRENCY || 10), 50));
  const backoffMs = Number(env.ERROR_BACKOFF_MS || 0);

  let idx = 0;
  async function worker() {
    while (true) {
      const myIdx = idx++;
      if (myIdx >= records.length) return;

      const record = records[myIdx];
      try {
        await processRecord(record, env);
      } catch (err) {
        console.error("Failed processing record", {
          messageId: record?.messageId,
          error: err?.message || String(err),
          stack: err?.stack,
          details: err?.details,
        });
        if (backoffMs > 0) await sleep(backoffMs);
      }
    }
  }

  const workers = [];
  for (let i = 0; i < Math.min(concurrency, records.length); i++) workers.push(worker());
  await Promise.all(workers);

  return { processed: records.length };
};